'use strict';

/**
 * run-all-tests.js
 * Master test runner for the Heady™ Auto-Testing Framework.
 * Orchestrates: existing Jest tests, auto-generated tests, integration tests,
 * CSL coherence suite, phi-scale tests, and regression detection.
 *
 * Usage:
 *   node scripts/run-all-tests.js          # run all tests
 *   node scripts/run-all-tests.js --gen    # also regenerate auto-test stubs
 *   node scripts/run-all-tests.js --save   # save current results as baseline
 *
 * Exit code 0 = all pass, 1 = failures or regressions detected
 *
 * Part of the Heady™ Auto-Testing Framework (Part C5)
 */

const { execSync, spawnSync } = require('child_process');
const path  = require('fs');
const fs    = require('fs');
const ppath = require('path');

const logger = require('../src/utils/logger');
const { IntegrationTestRunner } = require('../src/testing/integration-test-runner');
const { TestGenerator }          = require('../src/testing/test-generator');
const { RegressionDetector }     = require('../src/testing/regression-detector');
const { CoverageTracker }        = require('../src/testing/coverage-tracker');
const { PHI, PHI_INVERSE }       = require('../src/core/phi-scales');

// ---------------------------------------------------------------------------
// Parse CLI args
// ---------------------------------------------------------------------------
const args    = process.argv.slice(2);
const GEN     = args.includes('--gen');
const SAVE    = args.includes('--save');
const VERBOSE = args.includes('--verbose');

const ROOT = ppath.resolve(__dirname, '..');
const log  = logger.child ? logger.child({ module: 'RunAllTests' }) : logger;

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function section(title) {
  const bar = '─'.repeat(60);
  log.logSystem(`\n${bar}\n  ${title}\n${bar}`);
}

/** Run jest for a given pattern/config. Returns { passed, failed, total, output }. */
function runJest(pattern, extra = []) {
  const jestBin = ppath.join(ROOT, 'node_modules', '.bin', 'jest');
  const cmd     = fs.existsSync(jestBin) ? jestBin : 'jest';

  const result = spawnSync(
    cmd,
    [pattern, '--json', '--no-coverage', '--passWithNoTests', ...extra],
    { cwd: ROOT, encoding: 'utf8', timeout: 120000 }
  );

  let parsed = null;
  try {
    // jest --json outputs JSON on stdout
    parsed = JSON.parse(result.stdout || '{}');
  } catch (_) {
    // try last line fallback
    try {
      const lines = (result.stdout || '').split('\n').filter(Boolean);
      parsed = JSON.parse(lines[lines.length - 1]);
    } catch (__) {}
  }

  if (VERBOSE && result.stdout) log.info(result.stdout.slice(0, 2000));
  if (result.stderr) log.warn(result.stderr.slice(0, 500));

  const passed = parsed ? parsed.numPassedTests  || 0 : 0;
  const failed = parsed ? parsed.numFailedTests  || 0 : 0;
  const total  = passed + failed;

  return { passed, failed, total, exitCode: result.status };
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

async function main() {
  log.logSystem('RunAllTests starting', { GEN, SAVE, VERBOSE });
  const start = Date.now();

  const results = {};
  let globalFail = false;

  // ── Step 1: Optionally regenerate test stubs ──────────────────────────────
  if (GEN) {
    section('Step 1: Regenerating auto-test stubs');
    try {
      const gen    = new TestGenerator();
      const report = gen.generateAll();
      log.info('TestGenerator report', report);
      results.generation = report;
    } catch (err) {
      log.error('TestGenerator failed', { err: err.message });
      results.generation = { error: err.message };
    }
  }

  // ── Step 2: Existing hand-written tests ──────────────────────────────────
  section('Step 2: Existing tests (tests/ excluding auto-generated)');
  const existingResult = runJest('tests/', ['--testPathIgnorePatterns', 'auto-generated']);
  results.existing = existingResult;
  log.info('Existing tests', existingResult);
  if (existingResult.failed > 0) globalFail = true;

  // ── Step 3: Auto-generated tests ─────────────────────────────────────────
  section('Step 3: Auto-generated tests (tests/auto-generated/)');
  const autoResult = runJest('tests/auto-generated/');
  results.autoGenerated = autoResult;
  log.info('Auto-generated tests', autoResult);
  if (autoResult.failed > 0) globalFail = true;

  // ── Step 4: Integration tests ─────────────────────────────────────────────
  section('Step 4: Integration test runner');
  let integrationResult;
  try {
    const runner = new IntegrationTestRunner();
    integrationResult = await runner.run();
    results.integration = integrationResult;
    log.info('Integration test summary', {
      pass: integrationResult.pass,
      fail: integrationResult.fail,
      skip: integrationResult.skip,
    });
    if (integrationResult.fail > 0) globalFail = true;
  } catch (err) {
    log.error('Integration runner failed', { err: err.message });
    results.integration = { error: err.message };
    globalFail = true;
  }

  // ── Step 5: CSL coherence suite ───────────────────────────────────────────
  section('Step 5: CSL coherence suite');
  const cslResult = runJest('tests/auto-generated/core/semantic-logic.test.js');
  results.cslSuite = cslResult;
  log.info('CSL suite', cslResult);
  if (cslResult.failed > 0) globalFail = true;

  // ── Step 6: Phi-scale tests ───────────────────────────────────────────────
  section('Step 6: Phi-scale tests');
  const phiResult = runJest('tests/auto-generated/core/phi-scales.test.js');
  results.phiSuite = phiResult;
  log.info('Phi tests', phiResult);
  if (phiResult.failed > 0) globalFail = true;

  // ── Step 7: Coverage report ───────────────────────────────────────────────
  section('Step 7: Coverage analysis');
  try {
    const tracker = new CoverageTracker();
    tracker.scan();
    tracker.generateHTML();
    tracker.generateJSON();
    const coverageReport = tracker.getReport();
    results.coverage = {
      total:           coverageReport.total,
      coveragePercent: coverageReport.coveragePercent,
      counts:          coverageReport.counts,
    };
    log.info('Coverage report', results.coverage);
  } catch (err) {
    log.error('Coverage tracker failed', { err: err.message });
    results.coverage = { error: err.message };
  }

  // ── Step 8: Regression detection ─────────────────────────────────────────
  section('Step 8: Regression detection');
  const detector = new RegressionDetector();

  // Build a flat results array for the detector
  const flatResults = [];
  for (const [suite, data] of Object.entries(results)) {
    if (data && typeof data === 'object' && !data.error) {
      flatResults.push({ id: suite, name: suite, ...data });
    }
  }

  const regressionReport = detector.compare(flatResults);
  results.regression = regressionReport;

  if (regressionReport.hasRegression) {
    globalFail = true;
    log.warn('Regressions detected', { count: regressionReport.regressions.length });
  } else {
    log.info('No regressions detected');
  }

  if (SAVE) {
    detector.saveBaseline(flatResults);
    log.info('Baseline updated');
  }

  // ── Final summary ─────────────────────────────────────────────────────────
  section('Final Summary');

  const totalMs = Date.now() - start;
  const totalPassed = Object.values(results)
    .filter(r => typeof r === 'object' && typeof r.passed === 'number')
    .reduce((s, r) => s + r.passed, 0);
  const totalFailed = Object.values(results)
    .filter(r => typeof r === 'object' && typeof r.failed === 'number')
    .reduce((s, r) => s + r.failed, 0);

  const summary = {
    totalMs,
    totalPassed,
    totalFailed,
    globalFail,
    phiThreshold: PHI_INVERSE,
    suites: results,
  };

  log.logSystem('RunAllTests complete', {
    totalMs,
    passed: totalPassed,
    failed: totalFailed,
    outcome: globalFail ? 'FAIL' : 'PASS',
  });

  // Write unified report
  const reportsDir = ppath.join(ROOT, 'reports');
  fs.mkdirSync(reportsDir, { recursive: true });
  fs.writeFileSync(
    ppath.join(reportsDir, 'test-run-summary.json'),
    JSON.stringify(summary, null, 2),
    'utf8'
  );

  process.exit(globalFail ? 1 : 0);
}

main().catch(err => {
  log.error('RunAllTests top-level error', { err: err.message, stack: err.stack });
  process.exit(1);
});
